","/**
 * Detects device information including browser, OS, and device type
 * @returns {Object} - { browser, os, type }
 */
const getDeviceInfo = () => {
 const ua = navigator.userAgent;

 // Detect Browser
 let browser = 'Unknown';
 if (ua.includes('Edg/')) {
 browser = 'Microsoft Edge';
 } else if (ua.includes('Chrome/') && !ua.includes('Edg/') && !ua.includes('OPR/')) {
 browser = 'Google Chrome';
 } else if (ua.includes('Safari/') && !ua.includes('Chrome/')) {
 browser = 'Safari';
 } else if (ua.includes('Firefox/')) {
 browser = 'Firefox';
 } else if (ua.includes('Opera/') || ua.includes('OPR/')) {
 browser = 'Opera';
 } else if (ua.includes('Trident/') || ua.includes('MSIE ')) {
 browser = 'Internet Explorer';
 }

 // Detect OS
 let os = 'Unknown';

 if (ua.includes('iPhone') || ua.includes('iPad') || ua.includes('iPod')) {
 os = 'iOS';
 } else if (ua.includes('Win')) {
 os = 'Windows';
 } else if (ua.includes('Mac')) {
 os = 'macOS';
 } else if (ua.includes('CrOS')) {
 os = 'Chrome OS';
 } else if (ua.includes('Android')) {
 os = 'Android';
 } else if (ua.includes('X11') || ua.includes('Linux')) {
 os = 'Linux';
 }

 // Detect Device Type
 let type = 'desktop';
 if (/Mobi|Android|iPhone|iPad|iPod/i.test(ua)) {
 // Further differentiate between mobile and tablet
 if (/iPad|Android(?!.*Mobile)/i.test(ua)) {
 type = 'tablet';
 } else {
 type = 'mobile';
 }
 }

 return {
 browser,
 os,
 type
 };
};

const deviceInfoProvider = {
 provider: new Promise(resolve => {
 resolve(getDeviceInfo());
 }),
 mapper: (uxGlobals, result) => ({
 ...uxGlobals,
 deviceInfo: result
 })
