 const hrs = (u.getTime() - c.getTime()) / 3600000;
 if (hrs >= 0 && hrs < 8760) { totalResHours += hrs; resolvedCount++; }
 } else if (decision === "escalate") {
 escalated++;
 } else {
 // No decision yet = pending
 pending++;
 if (state === "1") {
 newClaims++;
 }
 }
 }

 return {
 total,
 approved,
 denied,
 escalated,
 pending,
 newClaims,
 approvalRate: total > 0 ? Math.round((approved / total) * 100) : 0,
 avgResolutionHours: resolvedCount > 0 ? Math.round(totalResHours / resolvedCount * 10) / 10 : 0,
 };
}

export async function fetchCustomers(): Promise<Array<{ value: string; label: string }>> {
 const resp = await fetch(
 `/api/now/table/core_company?sysparm_fields=sys_id,name&sysparm_limit=50&sysparm_display_value=all`,
 { headers: headers(), credentials: "same-origin" }
 );
 const { result } = await resp.json();
 return (result || []).map((r: any) => ({
 value: r.sys_id?.value || r.sys_id,
 label: r.name?.display_value || r.name?.value || r.name,
 }));
}
