","import React from "react";
import { ClaimMetrics } from "../services/ClaimService";

interface Props {
 metrics: ClaimMetrics;
}

interface Segment {
 label: string;
 value: number;
 color: string;
}

function getSegments(m: ClaimMetrics): Segment[] {
 return [
 { label: "Pending", value: m.pending, color: "rgb(var(--now-color--primary-2, 0,128,163))" },
 { label: "Approved", value: m.approved, color: "rgb(var(--now-color--grouping-green-2, 45,140,80))" },
 { label: "Denied", value: m.denied, color: "rgb(var(--now-color--grouping-red-2, 195,55,55))" },
 { label: "Escalated", value: m.escalated, color: "rgb(var(--now-color--grouping-amber-2, 200,140,0))" },
 ];
}

interface RingArcProps {
 startAngle: number;
 endAngle: number;
 color: string;
 radius: number;
 strokeWidth: number;
 cx: number;
 cy: number;
}

const RingArc: React.FC<RingArcProps> = ({ startAngle, endAngle, color, radius, strokeWidth, cx, cy }) => {
 const toRad = (deg: number) => ((deg - 90) * Math.PI) / 180;
 const x1 = cx + radius * Math.cos(toRad(startAngle));
 const y1 = cy + radius * Math.sin(toRad(startAngle));
 const x2 = cx + radius * Math.cos(toRad(endAngle));
 const y2 = cy + radius * Math.sin(toRad(endAngle));
 const largeArc = endAngle - startAngle > 180 ? 1 : 0;
 const d = `M ${x1} ${y1} A ${radius} ${radius} 0 ${largeArc} 1 ${x2} ${y2}`;

 return (
 <path
 d={d}
 fill="none"
 stroke={color}
 strokeWidth={strokeWidth}
 strokeLinecap="round"
 className="ring-segment"
 />
 );
};

export default function StatusChart({ metrics }: Props) {
 const segments = getSegments(metrics).filter((s) => s.value > 0);
 const total = segments.reduce((sum, s) => sum + s.value, 0);

 if (total === 0) {
 return (
 <div className="chart-container">
 <h3 className="chart-title">Claims by Status</h3>
 <div className="chart-empty">
 <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" className="chart-empty-icon">
 <circle cx="12" cy="12" r="10" />
 <line x1="8" y1="12" x2="16" y2="12" />
 </svg>
 <span>No data to display</span>
 </div>
 </div>
 );
 }

 const cx = 100;
 const cy = 100;
 const radius = 72;
 const strokeWidth = 22;
 const gap = 2; // degrees gap between segments

 let cumulative = 0;
 const paths = segments.map((seg, i) => {
 const segAngle = (seg.value / total) * 360;
 const startAngle = cumulative + (i === 0 ? 0 : gap / 2);
 cumulative += segAngle;
 const endAngle = cumulative - (i === segments.length - 1 ? 0 : gap / 2);
 return { ...seg, startAngle, endAngle };
 });

 return (
 <div className="chart-container">
 <h3 className="chart-title">Claims by Status</h3>
 <div className="chart-wrapper">
 <svg viewBox="0 0 200 200" className="donut-chart">
 {/* Background track */}
 <circle
 cx={cx}
 cy={cy}
 r={radius}
 fill="none"
 stroke="rgb(var(--now-color--divider-tertiary, 230,230,230))"
 strokeWidth={strokeWidth}
 opacity="0.4"
 />
 {/* Segments */}
 {paths.map((p) => (
 <RingArc
 key={p.label}
 startAngle={p.startAngle}
 endAngle={p.endAngle}
 color={p.color}
 radius={radius}
 strokeWidth={strokeWidth}
 cx={cx}
 cy={cy}
 />
 ))}
 {/* Center text */}
 <text x={cx} y={cy - 6} textAnchor="middle" className="chart-center-value">
 {total}
 </text>
 <text x={cx} y={cx + 12} textAnchor="middle" className="chart-center-label">
 Total
 </text>
 </svg>
 </div>
 <div className="chart-legend">
 {segments.map((s) => (
 <div key={s.label} className="legend-item">
 <span className="legend-dot" style={{ backgroundColor: s.color }} />
 <span className="legend-label">{s.label}</span>
 <span className="legend-value">{s.value}</span>
 </div>
 ))}
 </div>
 </div>
 );
}
