","import React from "react";
import { Select } from "@servicenow/react-components/Select";
import { Button } from "@servicenow/react-components/Button";

interface Props {
 dateFilter: string;
 customerFilter: string;
 priorityFilter: string;
 stateFilter: string;
 customers: Array<{ value: string; label: string }>;
 autoRefresh: boolean;
 onDateChange: (v: string) => void;
 onCustomerChange: (v: string) => void;
 onPriorityChange: (v: string) => void;
 onStateChange: (v: string) => void;
 onRefresh: () => void;
 onToggleAutoRefresh: () => void;
}

const DATE_OPTIONS = [
 { id: "", label: "All Time" },
 { id: "today", label: "Today" },
 { id: "week", label: "This Week" },
 { id: "month", label: "This Month" },
];

const PRIORITY_OPTIONS = [
 { id: "", label: "All Priorities" },
 { id: "1", label: "1 - Critical" },
 { id: "2", label: "2 - High" },
 { id: "3", label: "3 - Moderate" },
 { id: "4", label: "4 - Low" },
];

const STATE_OPTIONS = [
 { id: "", label: "All States" },
 { id: "1", label: "New" },
 { id: "3", label: "Resolved" },
 { id: "4", label: "Closed" },
 { id: "-5", label: "On Hold" },
];

export default function FilterBar(props: Props) {
 const customerItems = [
 { id: "", label: "All Customers" },
 ...props.customers.map((c) => ({ id: c.value, label: c.label })),
 ];

 return (
 <div className="filter-bar">
 <div className="filter-controls">
 <Select label="Date Range" items={DATE_OPTIONS} selectedItem={props.dateFilter} onSelectedItemSet={(e: any) => props.onDateChange(e.detail.item?.id || "")} />
 <Select label="Customer" items={customerItems} selectedItem={props.customerFilter} onSelectedItemSet={(e: any) => props.onCustomerChange(e.detail.item?.id || "")} />
 <Select label="Priority" items={PRIORITY_OPTIONS} selectedItem={props.priorityFilter} onSelectedItemSet={(e: any) => props.onPriorityChange(e.detail.item?.id || "")} />
 <Select label="State" items={STATE_OPTIONS} selectedItem={props.stateFilter} onSelectedItemSet={(e: any) => props.onStateChange(e.detail.item?.id || "")} />
 </div>
 <div className="filter-actions">
 <Button label="Refresh" variant="secondary" onClicked={props.onRefresh} />
 <Button label={props.autoRefresh ? "Auto: ON" : "Auto: OFF"} variant={props.autoRefresh ? "primary" : "tertiary"} onClicked={props.onToggleAutoRefresh} />
 </div>
 </div>
 );
}
","/* ===================================================================
 Warranty Claims Command Center — Premium Dashboard Styles
 =================================================================== */

/* --- Design Tokens & Variables --- */
:root {
 /* Base palette using ServiceNow design tokens with fallbacks */
 --dash-primary: rgb(var(--now-color--primary-2, 0, 128, 163));
 --dash-primary-light: rgba(0, 128, 163, 0.08);
 --dash-green: rgb(var(--now-color--grouping-green-2, 45, 140, 80));
 --dash-green-light: rgba(45, 140, 80, 0.08);
 --dash-amber: rgb(var(--now-color--grouping-amber-2, 200, 140, 0));
 --dash-amber-light: rgba(200, 140, 0, 0.08);
 --dash-red: rgb(var(--now-color--grouping-red-2, 195, 55, 55));
 --dash-red-light: rgba(195, 55, 55, 0.08);

 /* Surfaces */
 --dash-bg: rgb(var(--now-color--background-tertiary, 243, 244, 246));
 --dash-surface: rgb(var(--now-color--background-primary, 255, 255, 255));
 --dash-surface-elevated: rgb(var(--now-color--background-primary, 255, 255, 255));
 --dash-header-bg: rgb(var(--now-color--neutral-18, 22, 27, 34));
 --dash-header-text: rgb(var(--now-color--neutral-0, 255, 255, 255));

 /* Typography */
 --dash-text-primary: rgb(var(--now-color--text-primary, 29, 29, 29));
 --dash-text-secondary: rgb(var(--now-color--text-secondary, 82, 82, 82));
 --dash-text-tertiary: rgb(var(--now-color--text-tertiary, 135, 135, 135));

 /* Borders & Dividers */
 --dash-border: rgb(var(--now-color--divider-secondary, 224, 224, 224));
 --dash-border-light: rgb(var(--now-color--divider-tertiary, 240, 240, 240));

 /* Shadows */
 --dash-shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.04), 0 1px 3px rgba(0, 0, 0, 0.06);
 --dash-shadow-md: 0 2px 4px rgba(0, 0, 0, 0.04), 0 4px 12px rgba(0, 0, 0, 0.06);
 --dash-shadow-lg: 0 4px 6px rgba(0, 0, 0, 0.04), 0 10px 24px rgba(0, 0, 0, 0.08);
 --dash-shadow-hover: 0 6px 16px rgba(0, 0, 0, 0.08), 0 12px 32px rgba(0, 0, 0, 0.06);

 /* Spacing */
 --dash-gap-xs: 4px;
 --dash-gap-sm: 8px;
 --dash-gap-md: 16px;
 --dash-gap-lg: 24px;
 --dash-gap-xl: 32px;

 /* Radii */
 --dash-radius-sm: 6px;
 --dash-radius-md: 10px;
 --dash-radius-lg: 14px;

 /* Transitions */
 --dash-transition: 0.2s cubic-bezier(0.4, 0, 0.2, 1);
 --dash-transition-slow: 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

/* --- Reset & Base --- */
* {
 box-sizing: border-box;
}

.dashboard {
 min-height: 100vh;
 background: var(--dash-bg);
 font-family: var(--now-font-family, "Source Sans Pro", -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif);
 color: var(--dash-text-primary);
 padding: 0;
 margin: 0;
}

/* --- Header --- */
.dashboard-header {
 display: flex;
 align-items: center;
 justify-content: space-between;
 padding: 14px var(--dash-gap-lg);
 background: var(--dash-header-bg);
 color: var(--dash-header-text);
 margin: 0;
 position: sticky;
 top: 0;
 z-index: 100;
 box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
}

.header-left {
 display: flex;
 align-items: center;
 gap: 12px;
}

.header-logo {
 width: 28px;
 height: 28px;
 opacity: 0.9;
}

.dashboard-header h1 {
 margin: 0;
 font-size: 18px;
 font-weight: 600;
 letter-spacing: -0.01em;
 color: inherit;
}

.header-right {
 display: flex;
 align-items: center;
 gap: var(--dash-gap-md);
}

.last-updated {
 font-size: 12px;
 color: rgba(255, 255, 255, 0.6);
 font-weight: 400;
}

.refresh-indicator {
 display: inline-flex;
 align-items: center;
 gap: 6px;
 font-size: 12px;
 font-weight: 600;
 color: #4ade80;
 text-transform: uppercase;
 letter-spacing: 0.05em;
}

.live-dot {
 width: 8px;
 height: 8px;
 border-radius: 50%;
 background: #4ade80;
 animation: livePulse 2s ease-in-out infinite;
 box-shadow: 0 0 6px rgba(74, 222, 128, 0.6);
}

@keyframes livePulse {
 0%, 100% { opacity: 1; transform: scale(1); }
 50% { opacity: 0.5; transform: scale(0.85); }
}

/* --- Filter Bar --- */
.filter-bar {
 display: flex;
 align-items: center;
 justify-content: space-between;
 gap: var(--dash-gap-md);
 margin: var(--dash-gap-lg);
 margin-bottom: 0;
 padding: 10px var(--dash-gap-md);
 background: var(--dash-surface);
 border-radius: var(--dash-radius-md);
 border: 1px solid var(--dash-border-light);
 box-shadow: var(--dash-shadow-sm);
}

.filter-controls {
 display: flex;
 align-items: center;
 gap: var(--dash-gap-sm);
 flex-wrap: wrap;
 flex: 1;
}

.filter-actions {
 display: flex;
 align-items: center;
 gap: var(--dash-gap-sm);
 flex-shrink: 0;
}

/* --- Metrics Grid --- */
.metrics-grid {
 display: grid;
 grid-template-columns: repeat(4, 1fr);
 gap: var(--dash-gap-md);
 margin: var(--dash-gap-lg);
 margin-bottom: 0;
}

/* --- Metric Tiles --- */
.metric-tile {
 position: relative;
 display: flex;
 align-items: center;
 gap: var(--dash-gap-md);
 padding: 20px 22px;
 background: var(--dash-surface);
 border-radius: var(--dash-radius-lg);
 box-shadow: var(--dash-shadow-sm);
 border: 1px solid var(--dash-border-light);
 overflow: hidden;
 transition:
 transform var(--dash-transition),
 box-shadow var(--dash-transition),
 border-color var(--dash-transition);
 cursor: default;
}

.metric-tile::before {
 content: "";
 position: absolute;
 top: 0;
 left: 0;
 right: 0;
 bottom: 0;
 opacity: 0;
 transition: opacity var(--dash-transition);
 border-radius: inherit;
 pointer-events: none;
}

.metric-tile:hover {
 transform: translateY(-3px);
 box-shadow: var(--dash-shadow-hover);
 border-color: transparent;
}

.metric-tile:hover::before {
 opacity: 1;
}

/* Gradient variants */
.tile-gradient-blue {
 background: linear-gradient(135deg, rgba(0, 128, 163, 0.04) 0%, rgba(0, 128, 163, 0.01) 100%);
 border-left: 3px solid var(--dash-primary);
}
.tile-gradient-blue::before {
 background: linear-gradient(135deg, rgba(0, 128, 163, 0.08) 0%, rgba(0, 128, 163, 0.02) 100%);
}
.tile-gradient-blue:hover {
 border-left-color: var(--dash-primary);
}

.tile-gradient-green {
 background: linear-gradient(135deg, rgba(45, 140, 80, 0.04) 0%, rgba(45, 140, 80, 0.01) 100%);
 border-left: 3px solid var(--dash-green);
}
.tile-gradient-green::before {
 background: linear-gradient(135deg, rgba(45, 140, 80, 0.08) 0%, rgba(45, 140, 80, 0.02) 100%);
}
.tile-gradient-green:hover {
 border-left-color: var(--dash-green);
}

.tile-gradient-amber {
 background: linear-gradient(135deg, rgba(200, 140, 0, 0.04) 0%, rgba(200, 140, 0, 0.01) 100%);
 border-left: 3px solid var(--dash-amber);
}
.tile-gradient-amber::before {
 background: linear-gradient(135deg, rgba(200, 140, 0, 0.08) 0%, rgba(200, 140, 0, 0.02) 100%);
}
.tile-gradient-amber:hover {
 border-left-color: var(--dash-amber);
}

.tile-gradient-red {
 background: linear-gradient(135deg, rgba(195, 55, 55, 0.04) 0%, rgba(195, 55, 55, 0.01) 100%);
 border-left: 3px solid var(--dash-red);
}
.tile-gradient-red::before {
 background: linear-gradient(135deg, rgba(195, 55, 55, 0.08) 0%, rgba(195, 55, 55, 0.02) 100%);
}
.tile-gradient-red:hover {
 border-left-color: var(--dash-red);
}

/* --- Tile Icon --- */
.tile-icon-wrapper {
 display: flex;
 align-items: center;
 justify-content: center;
 width: 44px;
 height: 44px;
 border-radius: var(--dash-radius-sm);
 flex-shrink: 0;
}

.tile-gradient-blue .tile-icon-wrapper {
 background: var(--dash-primary-light);
 color: var(--dash-primary);
}

.tile-gradient-green .tile-icon-wrapper {
 background: var(--dash-green-light);
 color: var(--dash-green);
}

.tile-gradient-amber .tile-icon-wrapper {
 background: var(--dash-amber-light);
 color: var(--dash-amber);
}

.tile-gradient-red .tile-icon-wrapper {
 background: var(--dash-red-light);
 color: var(--dash-red);
}

.tile-icon-svg {
 width: 22px;
 height: 22px;
}

/* --- Tile Content --- */
.tile-content {
 display: flex;
 flex-direction: column;
 gap: 2px;
 min-width: 0;
}

.tile-value {
 font-size: 32px;
 font-weight: 700;
 line-height: 1.1;
 letter-spacing: -0.02em;
 color: var(--dash-text-primary);
}

.tile-label {
 font-size: 12px;
 font-weight: 500;
 color: var(--dash-text-tertiary);
 text-transform: uppercase;
 letter-spacing: 0.04em;
}

/* --- Tile Loading --- */
.tile-loading {
 width: 100%;
 height: 48px;
 display: flex;
 align-items: center;
}

.tile-loading-shimmer {
 width: 100%;
 height: 32px;
 border-radius: var(--dash-radius-sm);
 background: linear-gradient(
 90deg,
 var(--dash-border-light) 25%,
 rgba(255, 255, 255, 0.6) 50%,
 var(--dash-border-light) 75%
 );
 background-size: 200% 100%;
 animation: shimmer 1.5s ease-in-out infinite;
}

@keyframes shimmer {
 0% { background-position: 200% 0; }
 100% { background-position: -200% 0; }
}

/* --- Content Row --- */
.content-row {
 display: grid;
 grid-template-columns: 340px 1fr;
 gap: var(--dash-gap-lg);
 margin: var(--dash-gap-lg);
 align-items: start;
}

.content-left {
 background: var(--dash-surface);
 border-radius: var(--dash-radius-lg);
 border: 1px solid var(--dash-border-light);
 box-shadow: var(--dash-shadow-sm);
 padding: var(--dash-gap-lg);
 overflow: hidden;
}

.content-right {
 background: var(--dash-surface);
 border-radius: var(--dash-radius-lg);
 border: 1px solid var(--dash-border-light);
 box-shadow: var(--dash-shadow-sm);
 padding: var(--dash-gap-md);
 overflow: hidden;
 min-height: 400px;
}

/* --- Chart --- */
.chart-container {
 text-align: center;
}

.chart-title {
 margin: 0 0 var(--dash-gap-md) 0;
 font-size: 14px;
 font-weight: 600;
 color: var(--dash-text-primary);
 text-align: left;
 text-transform: uppercase;
 letter-spacing: 0.03em;
}

.chart-wrapper {
 display: flex;
 justify-content: center;
 padding: var(--dash-gap-sm) 0;
}

.donut-chart {
 width: 200px;
 height: 200px;
}

.ring-segment {
 transition: opacity var(--dash-transition);
}

.donut-chart:hover .ring-segment {
 opacity: 0.7;
}

.donut-chart:hover .ring-segment:hover {
 opacity: 1;
}

.chart-center-value {
 font-size: 28px;
 font-weight: 700;
 fill: var(--dash-text-primary);
 letter-spacing: -0.02em;
}

.chart-center-label {
 font-size: 11px;
 font-weight: 500;
 fill: var(--dash-text-tertiary);
 text-transform: uppercase;
 letter-spacing: 0.06em;
}

.chart-empty {
 display: flex;
 flex-direction: column;
 align-items: center;
 justify-content: center;
 gap: var(--dash-gap-sm);
 padding: 48px var(--dash-gap-lg);
 color: var(--dash-text-tertiary);
 font-size: 13px;
}

.chart-empty-icon {
 width: 36px;
 height: 36px;
 opacity: 0.4;
}

/* --- Legend --- */
.chart-legend {
 display: flex;
 flex-direction: column;
 gap: var(--dash-gap-sm);
 margin-top: var(--dash-gap-lg);
 padding-top: var(--dash-gap-md);
 border-top: 1px solid var(--dash-border-light);
}

.legend-item {
 display: flex;
 align-items: center;
 gap: var(--dash-gap-sm);
 font-size: 13px;
}

.legend-dot {
 width: 10px;
 height: 10px;
 border-radius: 3px;
 flex-shrink: 0;
}

.legend-label {
 color: var(--dash-text-secondary);
 flex: 1;
 text-align: left;
}

.legend-value {
 font-weight: 600;
 color: var(--dash-text-primary);
 font-variant-numeric: tabular-nums;
}

/* --- Responsive --- */
@media (max-width: 1100px) {
 .metrics-grid {
 grid-template-columns: repeat(2, 1fr);
 }

 .content-row {
 grid-template-columns: 1fr;
 }
}

@media (max-width: 720px) {
 .metrics-grid {
 grid-template-columns: 1fr;
 }

 .filter-bar {
 flex-direction: column;
 align-items: stretch;
 }

 .filter-controls {
 flex-direction: column;
 }

 .filter-actions {
 justify-content: flex-end;
 }

 .dashboard-header {
 flex-direction: column;
 align-items: flex-start;
 gap: var(--dash-gap-sm);
 }

 .header-right {
 width: 100%;
 justify-content: space-between;
 }
}
","export default function insertStyle(css, tagName = "style") {
 if (!css || typeof window === "undefined")
 return;
 if (tagName === "style") {
 const style = document.createElement("style");
 style.setAttribute("type", "text/css");
 style.innerHTML = css;
 document.head.appendChild(style);
 }
 else if (tagName === "link") {
 const link = document.createElement("link");
 link.setAttribute("rel", "stylesheet");
 link.setAttribute("href", css);
 document.head.appendChild(link);
 }
 return css;
}","import React, { useState, useEffect, useCallback, useRef } from "react";
import { NowRecordListConnected } from "@servicenow/react-components/NowRecordListConnected";
import { fetchMetrics, fetchCustomers, ClaimMetrics } from "./services/ClaimService";
import MetricsTiles from "./components/MetricsTiles";
import StatusChart from "./components/StatusChart";
import FilterBar from "./components/FilterBar";
import "./dashboard.css";

const TABLE = "x_snc_medwc_auto_0_warranty_claim";
const COLUMNS = "number,customer,device,priority,state,agent_decision,sys_created_on";

const EMPTY_METRICS: ClaimMetrics = {
 total: 0, approved: 0, denied: 0, escalated: 0,
 pending: 0, newClaims: 0, approvalRate: 0, avgResolutionHours: 0,
};

function formatTimestamp(date: Date): string {
 return date.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit" });
}

export default function App() {
 const [metrics, setMetrics] = useState<ClaimMetrics>(EMPTY_METRICS);
 const [loading, setLoading] = useState(true);
 const [customers, setCustomers] = useState<Array<{ value: string; label: string }>>([]);
 const [dateFilter, setDateFilter] = useState("");
 const [customerFilter, setCustomerFilter] = useState("");
 const [priorityFilter, setPriorityFilter] = useState("");
 const [stateFilter, setStateFilter] = useState("");
 const [autoRefresh, setAutoRefresh] = useState(true);
 const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
 const intervalRef = useRef<number | null>(null);

 const loadData = useCallback(async () => {
 setLoading(true);
 try {
 const m = await fetchMetrics(dateFilter, customerFilter, priorityFilter, stateFilter);
 setMetrics(m);
 setLastUpdated(new Date());
 } catch (e) { console.error("Failed to load metrics", e); }
 setLoading(false);
 }, [dateFilter, customerFilter, priorityFilter, stateFilter]);

 useEffect(() => { fetchCustomers().then(setCustomers); }, []);
 useEffect(() => { loadData(); }, [loadData]);

 useEffect(() => {
 if (autoRefresh) {
 intervalRef.current = window.setInterval(loadData, 30000);
 }
 return () => { if (intervalRef.current) clearInterval(intervalRef.current); };
 }, [autoRefresh, loadData]);

 const listKey = [dateFilter, customerFilter, priorityFilter, stateFilter].join("|");

 return (
 <div className="dashboard">
 <header className="dashboard-header">
 <div className="header-left">
 <svg className="header-logo" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
 <path d="M9 12l2 2 4-4" />
 <path d="M12 2a10 10 0 1 0 0 20 10 10 0 0 0 0-20z" />
 </svg>
 <h1>Warranty Claims Command Center</h1>
 </div>
 <div className="header-right">
 {lastUpdated && (
 <span className="last-updated">
 Last updated: {formatTimestamp(lastUpdated)}
 </span>
 )}
 {autoRefresh && (
 <span className="refresh-indicator">
 <span className="live-dot" />
 Live
 </span>
 )}
 </div>
 </header>
 <FilterBar
 dateFilter={dateFilter} customerFilter={customerFilter}
 priorityFilter={priorityFilter} stateFilter={stateFilter}
 customers={customers} autoRefresh={autoRefresh}
 onDateChange={setDateFilter} onCustomerChange={setCustomerFilter}
 onPriorityChange={setPriorityFilter} onStateChange={setStateFilter}
 onRefresh={loadData} onToggleAutoRefresh={() => setAutoRefresh(!autoRefresh)}
 />
 <MetricsTiles metrics={metrics} loading={loading} />
 <div className="content-row">
 <div className="content-left">
 <StatusChart metrics={metrics} />
 </div>
 <div className="content-right">
 <NowRecordListConnected
 key={listKey}
 table={TABLE}
 columns={COLUMNS}
 limit={10}
 hideHeader={true}
 />
 </div>
 </div>
 </div>
 );
}
","import React from "react";
import ReactDOM from "react-dom/client";
import App from "./app";

const root = document.getElementById("root");
if (root) {
 ReactDOM.createRoot(root).render(<App />);
}
